def space_fixture():
    dimensions = [Real(0.1, 0.9), Categorical(["foo", "bar", "baz"]), Integer(12, 18)]
    locations = [
        ("model_init_params", "a"),
        ("model_init_params", "b", "c"),
        ("model_extra_params", "e"),
    ]

    for i in range(len(dimensions)):
        setattr(dimensions[i], "location", locations[i])

    return Space(dimensions)

def csv_file(tmpdir, mol_smiles, label_a):
    fname = os.path.join(str(tmpdir), 'test.csv')
    df = pandas.DataFrame({
        'smiles': mol_smiles,
        'labelA': label_a
    })
    df.to_csv(fname)
    return fname

def csv_file_invalid(tmpdir):
    """CSV file with invalid SMILES"""
    fname = os.path.join(str(tmpdir), 'test_invalid.csv')
    df = pandas.DataFrame({
        'smiles': ['var', 'CN=C=O', 'hoge', 'Cc1ccccc1', 'CC1=CC2CC(CC1)O2'],
        'labelA': [0., 2.1, 0., 5.3, -1.2],
    })
    df.to_csv(fname)
    return fname

